insert into public.kc_articles(category_slug,title_en,title_bn,content_en,content_bn,keywords_en,keywords_bn,is_popular,status,sort_order) select 'account','How do I register correctly?','সঠিকভাবে রেজিস্টার করব কীভাবে?','Each user may register only one account. Use a correct 11-digit phone number beginning with 0. One IP address and one device may register only one account. Use your own invitation link when inviting friends.','প্রতিটি ব্যবহারকারী একটি অ্যাকাউন্ট রেজিস্টার করতে পারবেন। ০ দিয়ে শুরু হওয়া সঠিক ১১ সংখ্যার ফোন নম্বর ব্যবহার করুন। একই IP ও ডিভাইস থেকে একটি অ্যাকাউন্টই রেজিস্টার করা যাবে। বন্ধু আমন্ত্রণের সময় নিজের লিংক ব্যবহার করুন.','register phone ip device','register phone ip device',true,'published',1 where not exists(select 1 from public.kc_articles where title_en='How do I register correctly?');
insert into public.kc_articles(category_slug,title_en,title_bn,content_en,content_bn,keywords_en,keywords_bn,is_popular,status,sort_order) select 'account','Why can multiple accounts be restricted?','একাধিক অ্যাকাউন্ট কেন সীমাবদ্ধ হতে পারে?','Fake registration, multiple accounts, shared IP/device/phone/email, the same inviter, or abnormal batch registration may trigger risk review.','ভুয়া রেজিস্ট্রেশন, একাধিক অ্যাকাউন্ট, একই IP/ডিভাইস/ফোন/ইমেইল, একই ইনভাইটার বা অস্বাভাবিক ব্যাচ রেজিস্ট্রেশন রিস্ক রিভিউ শুরু করতে পারে.','multiple account risk','multiple account risk',false,'published',2 where not exists(select 1 from public.kc_articles where title_en='Why can multiple accounts be restricted?');
insert into public.kc_articles(category_slug,title_en,title_bn,content_en,content_bn,keywords_en,keywords_bn,is_popular,status,sort_order) select 'deposit','What deposit bonus points are available?','ডিপোজিটে কী বোনাস পয়েন্ট পাওয়া যায়?','First successful deposit: 100% bonus points once. Second successful deposit: 50% once. Daily deposits: 25%–50% according to the activity page. Points are based on the actual successful deposit amount.','প্রথম সফল ডিপোজিটে একবার ১০০% বোনাস পয়েন্ট। দ্বিতীয় সফল ডিপোজিটে একবার ৫০%। দৈনিক ডিপোজিটে অ্যাক্টিভিটি পেজ অনুযায়ী ২৫%–৫০%। পয়েন্ট প্রকৃত সফল ডিপোজিটের ওপর গণনা হয়.','first second daily deposit bonus','first second daily deposit bonus',true,'published',3 where not exists(select 1 from public.kc_articles where title_en='What deposit bonus points are available?');
insert into public.kc_articles(category_slug,title_en,title_bn,content_en,content_bn,keywords_en,keywords_bn,is_popular,status,sort_order) select 'deposit','Deposit bonus point examples','ডিপোজিট বোনাস পয়েন্টের উদাহরণ','500 BDT → first 500, second 250, daily 125–250. 1,000 → 1,000 / 500 / 250–500. 5,000 → 5,000 / 2,500 / 1,250–2,500. 10,000 → 10,000 / 5,000 / 2,500–5,000. 50,000 → 50,000 / 25,000 / 12,500–25,000.','৫০০ BDT → প্রথম ৫০০, দ্বিতীয় ২৫০, দৈনিক ১২৫–২৫০। ১,০০০ → ১,০০০ / ৫০০ / ২৫০–৫০০। ৫,০০০ → ৫,০০০ / ২,৫০০ / ১,২৫০–২,৫০০। ১০,০০০ → ১০,০০০ / ৫,০০০ / ২,৫০০–৫,০০০। ৫০,০০০ → ৫০,০০০ / ২৫,০০০ / ১২,৫০০–২৫,০০০।','500 1000 5000 10000 50000','500 1000 5000 10000 50000',false,'published',4 where not exists(select 1 from public.kc_articles where title_en='Deposit bonus point examples');
insert into public.kc_articles(category_slug,title_en,title_bn,content_en,content_bn,keywords_en,keywords_bn,is_popular,status,sort_order) select 'withdrawal','How long does a withdrawal take?','উইথড্র হতে কত সময় লাগে?','Withdrawals normally arrive in about 3 minutes and are expected within 30 minutes. If funds have not arrived after 30 minutes, contact official support.','সাধারণত প্রায় ৩ মিনিটে টাকা আসে এবং সর্বোচ্চ ৩০ মিনিটের মধ্যে আসার কথা। ৩০ মিনিট পরও না এলে অফিসিয়াল সাপোর্টে যোগাযোগ করুন.','withdrawal 3 30 minutes','withdrawal 3 30 minutes',true,'published',5 where not exists(select 1 from public.kc_articles where title_en='How long does a withdrawal take?');
insert into public.kc_articles(category_slug,title_en,title_bn,content_en,content_bn,keywords_en,keywords_bn,is_popular,status,sort_order) select 'withdrawal','What must I do before withdrawing?','উইথড্রের আগে কী করতে হবে?','Bind your own real BKASH or NAGAD account. Set a withdrawal password and keep it confidential. Incorrect wallet information may cause failure.','নিজের আসল BKASH অথবা NAGAD অ্যাকাউন্ট যুক্ত করুন। উইথড্র পাসওয়ার্ড সেট করে গোপন রাখুন। ভুল ওয়ালেট তথ্য দিলে উইথড্র ব্যর্থ হতে পারে.','bkash nagad password','bkash nagad password',true,'published',6 where not exists(select 1 from public.kc_articles where title_en='What must I do before withdrawing?');
insert into public.kc_articles(category_slug,title_en,title_bn,content_en,content_bn,keywords_en,keywords_bn,is_popular,status,sort_order) select 'bonus','What are bonus points?','বোনাস পয়েন্ট কী?','Bonus points are promotional rewards from deposits or tasks. They cannot be withdrawn directly or used for games. Complete the unlock task; the points then move to the Cash Wallet and can be withdrawn.','বোনাস পয়েন্ট হলো ডিপোজিট বা টাস্কের প্রোমোশনাল রিওয়ার্ড। এগুলো সরাসরি উইথড্র বা গেমে ব্যবহার করা যায় না। আনলক টাস্ক সম্পন্ন হলে পয়েন্ট Cash Wallet-এ যাবে এবং উইথড্র করা যাবে.','bonus points unlock cash wallet','bonus points unlock cash wallet',true,'published',7 where not exists(select 1 from public.kc_articles where title_en='What are bonus points?');
insert into public.kc_articles(category_slug,title_en,title_bn,content_en,content_bn,keywords_en,keywords_bn,is_popular,status,sort_order) select 'bonus','Where can I see bonus points?','বোনাস পয়েন্ট কোথায় দেখব?','View them in the locked-balance area on the home page or in Bonus Points inside the Personal Center.','হোম পেজের লক করা ব্যালেন্স অংশ অথবা Personal Center-এর Bonus Points সেকশনে দেখুন.','locked balance personal center','locked balance personal center',false,'published',8 where not exists(select 1 from public.kc_articles where title_en='Where can I see bonus points?');
insert into public.kc_articles(category_slug,title_en,title_bn,content_en,content_bn,keywords_en,keywords_bn,is_popular,status,sort_order) select 'activity','How does Gold Mine work?','Gold Mine কীভাবে কাজ করে?','Reach 100 valid betting on the same day to unlock it. Eight daily sessions: 11:00–11:10, 12:00–12:10, 15:00–15:10, 16:00–16:10, 18:00–18:10, 20:00–20:10, 21:00–21:10, 22:00–22:10. Up to 4 rounds per session. Rewards go to My Rewards. After claiming, complete 7× valid turnover before withdrawal.','একই দিনে ১০০ বৈধ বেটিং পূরণ করলে আনলক হবে। প্রতিদিন ৮টি সেশন: ১১:০০–১১:১০, ১২:০০–১২:১০, ১৫:০০–১৫:১০, ১৬:০০–১৬:১০, ১৮:০০–১৮:১০, ২০:০০–২০:১০, ২১:০০–২১:১০, ২২:০০–২২:১০। প্রতি সেশনে সর্বোচ্চ ৪ রাউন্ড। রিওয়ার্ড My Rewards-এ যাবে। দাবি করার পর উইথড্রের আগে ৭× টার্নওভার পূরণ করুন.','gold mine 7x','gold mine 7x',true,'published',9 where not exists(select 1 from public.kc_articles where title_en='How does Gold Mine work?');
insert into public.kc_articles(category_slug,title_en,title_bn,content_en,content_bn,keywords_en,keywords_bn,is_popular,status,sort_order) select 'activity','Aviator multiplier rewards','Aviator multiplier রিওয়ার্ড','Minimum bet 100 BDT. 15×=300 BDT, 20×=800, 30×=1,200, 50×=1,500, 80×=3,000, 120×=5,000. Contact support after qualifying. One claim per account per day.','সর্বনিম্ন বেট ১০০ BDT। ১৫×=৩০০ BDT, ২০×=৮০০, ৩০×=১,২০০, ৫০×=১,৫০০, ৮০×=৩,০০০, ১২০×=৫,০০০। শর্ত পূরণ হলে সাপোর্টে যোগাযোগ করুন। প্রতিদিন প্রতি অ্যাকাউন্টে একবার দাবি।','aviator 15x 20x 30x','aviator 15x 20x 30x',true,'published',10 where not exists(select 1 from public.kc_articles where title_en='Aviator multiplier rewards');
insert into public.kc_articles(category_slug,title_en,title_bn,content_en,content_bn,keywords_en,keywords_bn,is_popular,status,sort_order) select 'activity','How does Lucky Spin unlock?','Lucky Spin কীভাবে আনলক হয়?','Cumulative deposits of 500, 3,000 or 10,000 unlock Silver, Gold or Diamond levels. Each unlocked level offers 1 free spin per day, with chances to win prizes such as a motorcycle or Apple iPhone.','মোট ৫০০, ৩,০০০ বা ১০,০০০ ডিপোজিটে Silver, Gold বা Diamond লেভেল আনলক হয়। প্রতিটি আনলক লেভেলে প্রতিদিন ১টি ফ্রি স্পিন এবং মোটরসাইকেল বা Apple iPhone জেতার সুযোগ থাকে.','lucky spin 500 3000 10000','lucky spin 500 3000 10000',true,'published',11 where not exists(select 1 from public.kc_articles where title_en='How does Lucky Spin unlock?');
insert into public.kc_articles(category_slug,title_en,title_bn,content_en,content_bn,keywords_en,keywords_bn,is_popular,status,sort_order) select 'activity','Who can apply for the Rescue Fund?','Rescue Fund-এর জন্য কারা আবেদন করতে পারবেন?','Members with cumulative deposits of at least 300 may apply. The system evaluates losses and may provide up to 15% support. Higher VIP levels may receive better rates and dedicated support.','মোট ডিপোজিট কমপক্ষে ৩০০ হলে আবেদন করা যায়। সিস্টেম ক্ষতি মূল্যায়ন করে সর্বোচ্চ ১৫% পর্যন্ত সহায়তা দিতে পারে। উচ্চ VIP লেভেলে উন্নত রেট ও বিশেষ সাপোর্ট পাওয়া যেতে পারে.','rescue fund 15 vip','rescue fund 15 vip',false,'published',12 where not exists(select 1 from public.kc_articles where title_en='Who can apply for the Rescue Fund?');
insert into public.kc_articles(category_slug,title_en,title_bn,content_en,content_bn,keywords_en,keywords_bn,is_popular,status,sort_order) select 'activity','What is the 30-Day Deposit Challenge?','30-Day Deposit Challenge কী?','Five milestones: 2, 3, 7, 15 and 30 days. Higher milestones unlock larger rewards, with a possible top prize up to 50,000 BDT after completing 30 days.','৫টি মাইলস্টোন: ২, ৩, ৭, ১৫ ও ৩০ দিন। উচ্চ মাইলস্টোনে বড় রিওয়ার্ড এবং ৩০ দিন পূরণে সর্বোচ্চ ৫০,০০০ BDT পর্যন্ত পুরস্কারের সুযোগ।','30 day 50000','30 day 50000',false,'published',13 where not exists(select 1 from public.kc_articles where title_en='What is the 30-Day Deposit Challenge?');
insert into public.kc_articles(category_slug,title_en,title_bn,content_en,content_bn,keywords_en,keywords_bn,is_popular,status,sort_order) select 'task','Daily cumulative betting rewards','দৈনিক cumulative betting reward','≥800=8 BDT, ≥1,500=14, ≥3,000=30, ≥6,000=60, ≥12,000=130, ≥20,000=170.','≥৮০০=৮ BDT, ≥১,৫০০=১৪, ≥৩,০০০=৩০, ≥৬,০০০=৬০, ≥১২,০০০=১৩০, ≥২০,০০০=১৭০।','daily betting','daily betting',false,'published',14 where not exists(select 1 from public.kc_articles where title_en='Daily cumulative betting rewards');
insert into public.kc_articles(category_slug,title_en,title_bn,content_en,content_bn,keywords_en,keywords_bn,is_popular,status,sort_order) select 'task','Single valid bet daily rewards','একটি valid bet-এর দৈনিক রিওয়ার্ড','One valid bet per day: ≥500=5 BDT, ≥800=10, ≥1,000=15.','প্রতিদিন একটি বৈধ বেট: ≥৫০০=৫ BDT, ≥৮০০=১০, ≥১,০০০=১৫।','single bet','single bet',false,'published',15 where not exists(select 1 from public.kc_articles where title_en='Single valid bet daily rewards');
insert into public.kc_articles(category_slug,title_en,title_bn,content_en,content_bn,keywords_en,keywords_bn,is_popular,status,sort_order) select 'task','Single-game profit rewards','একটি গেমে লাভের রিওয়ার্ড','Profit in any single game: ≥50=2 BDT, ≥100=5, ≥200=12. Available daily.','যেকোনো একটি গেমে লাভ: ≥৫০=২ BDT, ≥১০০=৫, ≥২০০=১২। প্রতিদিন অংশ নেওয়া যায়।','single game profit','single game profit',false,'published',16 where not exists(select 1 from public.kc_articles where title_en='Single-game profit rewards');
insert into public.kc_articles(category_slug,title_en,title_bn,content_en,content_bn,keywords_en,keywords_bn,is_popular,status,sort_order) select 'task','Weekly valid betting rewards','সাপ্তাহিক valid betting reward','≥5,000=40 BDT, ≥12,000=150, ≥25,000=400, ≥50,000=900, ≥100,000=2,000.','≥৫,০০০=৪০ BDT, ≥১২,০০০=১৫০, ≥২৫,০০০=৪০০, ≥৫০,০০০=৯০০, ≥১,০০,০০০=২,০০০।','weekly betting','weekly betting',false,'published',17 where not exists(select 1 from public.kc_articles where title_en='Weekly valid betting rewards');
insert into public.kc_articles(category_slug,title_en,title_bn,content_en,content_bn,keywords_en,keywords_bn,is_popular,status,sort_order) select 'agent','What rewards can agents receive?','এজেন্টরা কী কী রিওয়ার্ড পেতে পারেন?','Valid invitation rewards, first-deposit rewards, second-deposit rewards, six-level rebates and daily agent salary. Qualified agents may receive platform services and traffic support.','Valid invitation reward, first-deposit reward, second-deposit reward, ছয়-লেভেল রিবেট এবং দৈনিক এজেন্ট স্যালারি। যোগ্য এজেন্ট প্ল্যাটফর্ম সার্ভিস ও ট্রাফিক সাপোর্টও পেতে পারেন।','agent rewards','agent rewards',true,'published',18 where not exists(select 1 from public.kc_articles where title_en='What rewards can agents receive?');
insert into public.kc_articles(category_slug,title_en,title_bn,content_en,content_bn,keywords_en,keywords_bn,is_popular,status,sort_order) select 'agent','Daily and weekly invitation rewards','দৈনিক ও সাপ্তাহিক invitation reward','Daily: 2 people=150 BDT, 5=600, 10=1,500, 20=2,500, 50=5,500. Weekly extra: 10=300, 20=700, 50=1,800, 100=3,800, 300=7,000, 500=13,000.','দৈনিক: ২ জন=১৫০ BDT, ৫=৬০০, ১০=১,৫০০, ২০=২,৫০০, ৫০=৫,৫০০। সাপ্তাহিক অতিরিক্ত: ১০=৩০০, ২০=৭০০, ৫০=১,৮০০, ১০০=৩,৮০০, ৩০০=৭,০০০, ৫০০=১৩,০০০।','invitation reward','invitation reward',false,'published',19 where not exists(select 1 from public.kc_articles where title_en='Daily and weekly invitation rewards');
insert into public.kc_articles(category_slug,title_en,title_bn,content_en,content_bn,keywords_en,keywords_bn,is_popular,status,sort_order) select 'agent','How is daily agent salary unlocked?','দৈনিক এজেন্ট স্যালারি কীভাবে আনলক হয়?','Meet all targets for L1–L6 depositing members, total L1–L6 deposits, L1 deposit amount and L1 depositing members. Salary uses the highest level achieved that day and does not stack. Contact the 9M Agent Manager the next day to claim.','L1–L6 ডিপোজিটকারী সদস্য, মোট L1–L6 ডিপোজিট, L1 ডিপোজিট পরিমাণ এবং L1 সদস্য—সব লক্ষ্য পূরণ করুন। ওই দিনের সর্বোচ্চ লেভেল অনুযায়ী স্যালারি দেওয়া হয় এবং যোগ হয় না। পরের দিন 9M Agent Manager-এর সাথে যোগাযোগ করুন।','agent salary l1 l6','agent salary l1 l6',false,'published',20 where not exists(select 1 from public.kc_articles where title_en='How is daily agent salary unlocked?');
insert into public.kc_articles(category_slug,title_en,title_bn,content_en,content_bn,keywords_en,keywords_bn,is_popular,status,sort_order) select 'game','Which game providers are available?','কোন গেম প্রোভাইডার পাওয়া যায়?','Available providers include PG, JILI, SPRIBE, CQ9, INOUT, JDB, TADA, MG, FACHAI, JOKER, WG, HABANERO, NG, BGAMING, PP, ASKME SLOT, EVOPLAY, BBIN and PLAYTECH.','PG, JILI, SPRIBE, CQ9, INOUT, JDB, TADA, MG, FACHAI, JOKER, WG, HABANERO, NG, BGAMING, PP, ASKME SLOT, EVOPLAY, BBIN এবং PLAYTECH পাওয়া যায়।','game providers','game providers',false,'published',21 where not exists(select 1 from public.kc_articles where title_en='Which game providers are available?');
insert into public.kc_articles(category_slug,title_en,title_bn,content_en,content_bn,keywords_en,keywords_bn,is_popular,status,sort_order) select 'support','When should I contact official support?','কখন অফিসিয়াল সাপোর্টে যোগাযোগ করব?','Contact support when a withdrawal has not arrived after 30 minutes, when account or wallet information needs review, or when an activity needs manual reward verification. Prepare your user ID, phone number, time, amount and screenshots.','উইথড্র ৩০ মিনিট পরও না এলে, অ্যাকাউন্ট বা ওয়ালেট তথ্য যাচাই দরকার হলে, অথবা কোনো অ্যাক্টিভিটিতে ম্যানুয়াল রিওয়ার্ড ভেরিফিকেশন লাগলে সাপোর্টে যোগাযোগ করুন। User ID, ফোন নম্বর, সময়, পরিমাণ ও স্ক্রিনশট প্রস্তুত রাখুন।','support 30 minutes','support 30 minutes',true,'published',22 where not exists(select 1 from public.kc_articles where title_en='When should I contact official support?');
insert into public.kc_announcements(title_en,title_bn,body_en,body_bn,is_active,sort_order) select 'Welcome to the 9M Knowledge Center','9M Knowledge Center-এ স্বাগতম','Search platform rules, rewards, activities and account help.','প্ল্যাটফর্ম নিয়ম, রিওয়ার্ড, অ্যাক্টিভিটি ও অ্যাকাউন্ট সহায়তা খুঁজুন।',true,1 where not exists(select 1 from public.kc_announcements);
insert into public.kc_service_status(service_key,label_en,label_bn,state,sort_order) values('deposit','Deposit','ডিপোজিট','normal',10),('withdrawal','Withdrawal','উইথড্র','normal',20),('games','Games','গেমস','normal',30),('support','Support','সাপোর্ট','normal',40) on conflict(service_key) do update set label_en=excluded.label_en,label_bn=excluded.label_bn,state=excluded.state,sort_order=excluded.sort_order;
insert into public.kc_support_channels(channel_key,label_en,label_bn,url,icon,is_active,sort_order) values('telegram','Telegram Support','টেলিগ্রাম সাপোর্ট','https://t.me/VIP_9m068','✈️',true,10) on conflict(channel_key) do update set label_en=excluded.label_en,label_bn=excluded.label_bn,url=excluded.url,icon=excluded.icon,is_active=true;
